using RecoveredModuleExitCallback = void (*)();
using RecoveredModuleExitDispatcher = void (*)(RecoveredModuleExitCallback);

struct RecoveredModuleRuntimeOperations8070 {
    void* context;
    void* dsoHandle;
    void (*finalize)(void* context, void* dsoHandle);
    std::int32_t (*registerAtExit)(
            void* context,
            RecoveredModuleExitDispatcher dispatcher,
            RecoveredModuleExitCallback callback,
            void* dsoHandle);
};

// Compiler/runtime scaffolding at the first five ARM64 FDEs.  0x8070
// tail-calls __cxa_finalize with the image's fixed DSO handle.  0x8080 is a
// no-op callback and 0x8088 is its tail alias.  0x8090 invokes a non-null
// callback and otherwise returns.  0x80a4 registers 0x8090 through
// __cxa_atexit, using its incoming callback as the registered argument and the
// same fixed DSO handle.  The source model receives the image-local handle and
// runtime functions through operations instead of embedding a relocated VMA.
void runRecoveredModuleFinalize8070(
        const RecoveredModuleRuntimeOperations8070& operations) {
    operations.finalize(operations.context, operations.dsoHandle);
}

void runRecoveredModuleNoOp8080() {}

void runRecoveredModuleNoOpAlias8088() {
    runRecoveredModuleNoOp8080();
}

void runRecoveredModuleExitDispatcher8090(
        RecoveredModuleExitCallback callback) {
    if (callback != nullptr) callback();
}

std::int32_t runRecoveredModuleAtExitRegistration80a4(
        RecoveredModuleExitCallback callback,
        const RecoveredModuleRuntimeOperations8070& operations) {
    return operations.registerAtExit(
            operations.context,
            runRecoveredModuleExitDispatcher8090,
            callback,
            operations.dsoHandle);
}

struct RecoveredModuleRuntimeRegressionState8070 {
    std::uint32_t finalizeCalls = 0;
    std::uint32_t callbackCalls = 0;
    std::uint32_t registrationCalls = 0;
    void* finalizedDso = nullptr;
    void* registeredDso = nullptr;
    RecoveredModuleExitDispatcher dispatcher = nullptr;
    RecoveredModuleExitCallback callback = nullptr;
};

RecoveredModuleRuntimeRegressionState8070*&
recoveredModuleRuntimeRegressionState8070() {
    static RecoveredModuleRuntimeRegressionState8070* state = nullptr;
    return state;
}

void recoveredModuleRuntimeFinalize8070(void* context, void* dsoHandle) {
    auto* state = static_cast<RecoveredModuleRuntimeRegressionState8070*>(
            context);
    ++state->finalizeCalls;
    state->finalizedDso = dsoHandle;
}

void recoveredModuleRuntimeCallback8070() {
    ++recoveredModuleRuntimeRegressionState8070()->callbackCalls;
}

std::int32_t recoveredModuleRuntimeRegister8070(
        void* context,
        RecoveredModuleExitDispatcher dispatcher,
        RecoveredModuleExitCallback callback,
        void* dsoHandle) {
    auto* state = static_cast<RecoveredModuleRuntimeRegressionState8070*>(
            context);
    ++state->registrationCalls;
    state->dispatcher = dispatcher;
    state->callback = callback;
    state->registeredDso = dsoHandle;
    return 37;
}

bool recoveredModuleRuntimeScaffolding8070Regression() {
    RecoveredModuleRuntimeRegressionState8070 state;
    recoveredModuleRuntimeRegressionState8070() = &state;
    int dsoHandle = 0;
    const RecoveredModuleRuntimeOperations8070 operations = {
        &state,
        &dsoHandle,
        recoveredModuleRuntimeFinalize8070,
        recoveredModuleRuntimeRegister8070,
    };
    runRecoveredModuleFinalize8070(operations);
    runRecoveredModuleNoOp8080();
    runRecoveredModuleNoOpAlias8088();
    runRecoveredModuleExitDispatcher8090(nullptr);
    runRecoveredModuleExitDispatcher8090(
            recoveredModuleRuntimeCallback8070);
    const std::int32_t registrationStatus =
            runRecoveredModuleAtExitRegistration80a4(
                    recoveredModuleRuntimeCallback8070, operations);
    if (state.dispatcher != nullptr) {
        state.dispatcher(state.callback);
    }
    recoveredModuleRuntimeRegressionState8070() = nullptr;
    return state.finalizeCalls == 1
            && state.callbackCalls == 2
            && state.registrationCalls == 1
            && state.finalizedDso == &dsoHandle
            && state.registeredDso == &dsoHandle
            && state.dispatcher == runRecoveredModuleExitDispatcher8090
            && state.callback == recoveredModuleRuntimeCallback8070
            && registrationStatus == 37;
}

