// Recovered property-materialization subpipeline inside
// libsigner.so+0x8746c..0x8f56c.  Both ABIs use one zeroed 0x60-byte stack
// buffer for all thirteen d4678 reads, ignore the property-reader return,
// measure the resulting NUL-terminated value, allocate length+1, copy it and
// publish the owned pointer at the fixed scratch offset.  Publication is
// intentionally delayed until immediately before the next read, matching the
// flattened native pipeline; the final CPU ABI-list pointer is published after
// the loop.  Allocation failure clears the current slot and returns status 2,
// leaving earlier publications in place for the caller's cleanup path.
//
// No device value is embedded here.  A caller may provide real Android
// properties, a user-authored profile, empty strings, or a deterministic test
// profile through readProperty.
std::uint32_t runRecoveredDetectorProperties8746c(
        RecoveredDetectorScratch868b4* scratch,
        const RecoveredDetectorPropertyOperations8746c& operations) {
    std::array<char, 0x60> propertyValue{};
    const char** pendingSlot = nullptr;
    const char* pendingValue = nullptr;

    for (const auto& descriptor : kRecoveredDetectorPropertyDescriptors8746c) {
        if (pendingSlot != nullptr) {
            *pendingSlot = pendingValue;
        }

        static_cast<void>(operations.readProperty(
                descriptor.propertyName, propertyValue.data()));
        std::uint64_t length = 0;
        while (propertyValue[length] != '\0') ++length;

        auto* allocation = static_cast<char*>(operations.allocate(length + 1));
        const char** currentSlot = recoveredDetectorPropertySlot8746c(
                scratch, descriptor.scratchOffset);
        if (allocation == nullptr) {
            *currentSlot = nullptr;
            return 2;
        }
        for (std::uint64_t index = 0; index < length; ++index) {
            allocation[index] = propertyValue[index];
        }
        allocation[length] = '\0';
        pendingSlot = currentSlot;
        pendingValue = allocation;
    }

    *pendingSlot = pendingValue;
    return 0;
}

struct RecoveredDetectorPropertyRegressionState8746c {
    std::array<std::string, 13> values;
    std::array<std::array<char, 0x60>, 13> allocations{};
    std::vector<std::string> reads;
    std::vector<std::uint64_t> allocationSizes;
    std::size_t failAllocation = static_cast<std::size_t>(-1);
};

RecoveredDetectorPropertyRegressionState8746c*&
recoveredDetectorPropertyRegressionState8746c() {
    static RecoveredDetectorPropertyRegressionState8746c* state = nullptr;
    return state;
}

std::int32_t recoveredDetectorPropertyRegressionRead8746c(
        const char* propertyName, char* outputValue) {
    auto* state = recoveredDetectorPropertyRegressionState8746c();
    const auto begin = kRecoveredDetectorPropertyDescriptors8746c.begin();
    const auto end = kRecoveredDetectorPropertyDescriptors8746c.end();
    const auto found = std::find_if(begin, end,
            [propertyName](const RecoveredDetectorPropertyDescriptor8746c& item) {
                return std::strcmp(item.propertyName, propertyName) == 0;
            });
    if (found == end) return -1;
    const std::size_t index = static_cast<std::size_t>(found - begin);
    state->reads.emplace_back(propertyName);
    const auto& value = state->values[index];
    std::memcpy(outputValue, value.data(), value.size());
    outputValue[value.size()] = '\0';
    return index == 6 ? -7 : 17;
}

void* recoveredDetectorPropertyRegressionAllocate8746c(std::uint64_t size) {
    auto* state = recoveredDetectorPropertyRegressionState8746c();
    const std::size_t index = state->allocationSizes.size();
    state->allocationSizes.push_back(size);
    if (index == state->failAllocation) return nullptr;
    return state->allocations[index].data();
}

bool recoveredDetectorProperties8746cRegression() {
    const RecoveredDetectorPropertyOperations8746c operations = {
        recoveredDetectorPropertyRegressionRead8746c,
        recoveredDetectorPropertyRegressionAllocate8746c,
    };
    RecoveredDetectorPropertyRegressionState8746c state;
    for (std::size_t index = 0; index < state.values.size(); ++index) {
        state.values[index] = index == 2
                ? std::string()
                : "user-value-" + std::to_string(index);
    }
    recoveredDetectorPropertyRegressionState8746c() = &state;

    RecoveredDetectorScratch868b4 scratch{};
    std::uint32_t status = runRecoveredDetectorProperties8746c(
            &scratch, operations);
    std::vector<std::string> expectedReads;
    std::vector<std::uint64_t> expectedSizes;
    bool success = status == 0;
    for (std::size_t index = 0;
            index < kRecoveredDetectorPropertyDescriptors8746c.size(); ++index) {
        const auto& descriptor = kRecoveredDetectorPropertyDescriptors8746c[index];
        expectedReads.emplace_back(descriptor.propertyName);
        expectedSizes.push_back(state.values[index].size() + 1);
        const char* value = *recoveredDetectorPropertySlot8746c(
                &scratch, descriptor.scratchOffset);
        success = success && value != nullptr && state.values[index] == value;
    }
    success = success && state.reads == expectedReads
            && state.allocationSizes == expectedSizes;

    for (std::size_t failure = 0;
            success && failure < kRecoveredDetectorPropertyDescriptors8746c.size();
            ++failure) {
        state.reads.clear();
        state.allocationSizes.clear();
        state.failAllocation = failure;
        scratch = {};
        status = runRecoveredDetectorProperties8746c(&scratch, operations);
        success = status == 2
                && state.reads.size() == failure + 1
                && state.allocationSizes.size() == failure + 1;
        for (std::size_t index = 0;
                success && index < kRecoveredDetectorPropertyDescriptors8746c.size();
                ++index) {
            const auto& descriptor = kRecoveredDetectorPropertyDescriptors8746c[index];
            const char* value = *recoveredDetectorPropertySlot8746c(
                    &scratch, descriptor.scratchOffset);
            success = index < failure
                    ? value != nullptr && state.values[index] == value
                    : value == nullptr;
        }
    }

    recoveredDetectorPropertyRegressionState8746c() = nullptr;
    return success;
}

