class BionicRandom {
public:
    explicit BionicRandom(std::uint32_t seedValue) {
        seed(seedValue);
    }

    std::uint32_t next() {
        state_[front_] += state_[rear_];
        const std::uint32_t value = (state_[front_] >> 1) & 0x7fffffffU;
        front_ = (front_ + 1) % state_.size();
        rear_ = (rear_ + 1) % state_.size();
        return value;
    }

private:
    void seed(std::uint32_t value) {
        state_[0] = value;
        for (std::size_t i = 1; i < state_.size(); ++i) {
            const std::int64_t previous = static_cast<std::int32_t>(state_[i - 1]);
            const std::int64_t high = previous / 127773;
            const std::int64_t low = previous % 127773;
            std::int64_t nextValue = 16807 * low - 2836 * high;
            if (nextValue <= 0) nextValue += 0x7fffffff;
            state_[i] = static_cast<std::uint32_t>(nextValue);
        }
        front_ = 3;
        rear_ = 0;
        for (std::size_t i = 0; i < 10 * state_.size(); ++i) next();
    }

    std::array<std::uint32_t, 31> state_{};
    std::size_t front_ = 3;
    std::size_t rear_ = 0;
};

// libsigner.so+0x12f2f8 stores the caller's 32-bit seed as a zero-extended
// 64-bit state value. A null state pointer is an intentional no-op.
void recoveredParkMillerSeed12f2f8(
        std::uint64_t* state,
        std::uint32_t seed) {
    if (state != nullptr) *state = seed;
}

// libsigner.so+0x12f29c is the Park-Miller minimal-standard generator used
// only by the correction-basis permutation builder. State zero is replaced
// by 123459876. The native code keeps the unmasked 64-bit intermediate in
// memory and returns its low 31 bits.
std::uint32_t recoveredParkMillerNext12f29c(std::uint64_t* state) {
    std::uint64_t value = *state;
    if (value == 0) value = 123459876U;
    const std::uint64_t quotient = value / 127773U;
    const std::uint64_t remainder = value
            + quotient * static_cast<std::uint64_t>(-127773LL);
    value = remainder * 16807U
            + quotient * static_cast<std::uint64_t>(-2836LL);
    if ((value & (std::uint64_t{1} << 63)) != 0) {
        value += 0x7fffffffU;
    }
    *state = value;
    return static_cast<std::uint32_t>(value) & 0x7fffffffU;
}

// libsigner.so+0x12f298 is a one-instruction tail alias of 0x12f29c.
std::uint32_t recoveredParkMillerNext12f298(std::uint64_t* state) {
    return recoveredParkMillerNext12f29c(state);
}

// Complete libsigner.so+0x134f40..0x135050. The output starts as sixteen
// zero bytes. For each index i, the helper chooses j = next() % (i + 1),
// moves output[j] to output[i], then writes i to output[j]. This is the
// incremental Fisher-Yates construction of a permutation of 0..15.
std::array<std::uint8_t, 16> recoveredPermutationShuffle134f40(
        std::uint64_t* state) {
    std::array<std::uint8_t, 16> output{};
    for (std::uint32_t index = 0; index < output.size(); ++index) {
        const std::uint32_t selected = recoveredParkMillerNext12f298(state)
                % (index + 1U);
        output[index] = output[selected];
        output[selected] = static_cast<std::uint8_t>(index);
    }
    return output;
}

bool recoveredProtectedRandomHelpersRegression() {
    std::uint64_t state = 0xaaaaaaaaaaaaaaaaULL;
    recoveredParkMillerSeed12f2f8(&state, 1);
    if (state != 1 || recoveredParkMillerNext12f298(&state) != 16807U
            || state != 16807U
            || recoveredParkMillerNext12f29c(&state) != 282475249U
            || state != 282475249U) {
        return false;
    }

    recoveredParkMillerSeed12f2f8(nullptr, 0x12345678U);
    recoveredParkMillerSeed12f2f8(&state, 0);
    if (recoveredParkMillerNext12f29c(&state) != 520932930U
            || state != 520932930U) {
        return false;
    }

    recoveredParkMillerSeed12f2f8(&state, 1);
    const std::array<std::uint8_t, 16> expected = {{
        4, 1, 6, 2, 0, 11, 13, 15, 8, 9, 7, 12, 14, 10, 3, 5
    }};
    return recoveredPermutationShuffle134f40(&state) == expected
            && state == 0x43cd3747U;
}

// Complete libsigner.so+0x135050..0x13531c (x86_64 +0x12f21b).
// The helper treats the sixteen input halfwords as a 16x16 bit matrix,
// transposes it using MSB-first row and column indices into a zeroed local
// array, then copies all sixteen transformed halfwords back to the caller.
void recoveredCorrectionBasisTranspose135050(std::uint16_t* words) {
    std::array<std::uint16_t, 16> transposed{};
    for (std::size_t source = 0; source < 16; ++source) {
        const std::uint16_t destinationBit = static_cast<std::uint16_t>(
                std::uint16_t{1} << (15U - source));
        for (std::size_t destination = 0; destination < 16; ++destination) {
            const std::uint16_t sourceBit = static_cast<std::uint16_t>(
                    std::uint16_t{1} << (15U - destination));
            if ((words[source] & sourceBit) != 0) {
                transposed[destination] = static_cast<std::uint16_t>(
                        transposed[destination] | destinationBit);
            }
        }
    }
    std::copy(transposed.begin(), transposed.end(), words);
}

bool recoveredCorrectionBasisTranspose135050Regression() {
    std::array<std::uint16_t, 16> words = {{
        0x1234, 0xabcd, 0x0000, 0xffff,
        0x8001, 0x00ff, 0xff00, 0x5555,
        0xaaaa, 0x1357, 0x2468, 0xdead,
        0xbeef, 0xcafe, 0xbabe, 0x0f0f
    }};
    constexpr std::array<std::uint16_t, 16> expected = {{
        0x5a9e, 0x1314, 0x52aa, 0x935a,
        0x529f, 0x1339, 0xd2df, 0x5341,
        0x549e, 0x556c, 0x94be, 0x9546,
        0x54bf, 0xd55f, 0x14cf, 0x5d59
    }};
    recoveredCorrectionBasisTranspose135050(words.data());
    if (words != expected) return false;
    recoveredCorrectionBasisTranspose135050(words.data());
    return words == std::array<std::uint16_t, 16>{
        0x1234, 0xabcd, 0x0000, 0xffff,
        0x8001, 0x00ff, 0xff00, 0x5555,
        0xaaaa, 0x1357, 0x2468, 0xdead,
        0xbeef, 0xcafe, 0xbabe, 0x0f0f
    };
}

struct RecoveredEntropySeed12f3acOperations {
    std::int32_t (*access)(const char* path, std::int32_t mode);
    std::int64_t (*openAt)(std::int64_t syscallNumber,
            std::int32_t directoryDescriptor,
            const char* path,
            std::int32_t flags,
            std::int32_t mode);
    std::int64_t (*read)(std::int32_t descriptor,
            void* output,
            std::size_t length);
    std::int32_t (*close)(std::int32_t descriptor);
    std::int32_t (*getTimeOfDay)(
            std::int64_t* seconds,
            std::int64_t* microseconds);
    std::int32_t (*getPid)();
};

// Complete libsigner.so+0x12f3ac..0x12fa24 (x86_64 +0x129b71).
// A null output is a no-op. Otherwise the output is cleared, the once-decoded
// path "/dev/urandom" is checked with R_OK, and ARM64 openat syscall 56 is
// used with AT_FDCWD and O_CLOEXEC. Exactly eight read bytes are accepted.
// An access/open/short-read failure falls back to low32(tv_sec) XOR
// low32(tv_usec) XOR (getpid()<<16). Read descriptors are closed regardless
// of the read length; all syscall and close return values except the explicit
// access/open/read gates are ignored.
void runRecoveredEntropySeed12f3ac(
        std::uint64_t* output,
        const RecoveredEntropySeed12f3acOperations& operations) {
    if (output == nullptr) return;
    *output = 0;

    bool useFallback = operations.access("/dev/urandom", 4) != 0;
    if (!useFallback) {
        const std::int64_t descriptor = operations.openAt(
                56, -100, "/dev/urandom", 0x80000, 0);
        if (descriptor < 0) {
            useFallback = true;
        } else {
            const std::int64_t readLength = operations.read(
                    static_cast<std::int32_t>(descriptor), output, 8);
            static_cast<void>(operations.close(
                    static_cast<std::int32_t>(descriptor)));
            useFallback = readLength != 8;
        }
    }

    if (useFallback) {
        std::int64_t seconds = 0;
        std::int64_t microseconds = 0;
        static_cast<void>(operations.getTimeOfDay(
                &seconds, &microseconds));
        const std::uint32_t seed = static_cast<std::uint32_t>(seconds)
                ^ static_cast<std::uint32_t>(microseconds)
                ^ (static_cast<std::uint32_t>(operations.getPid()) << 16);
        *output = seed;
    }
}

enum class RecoveredEntropySeed12f3acEvent : std::uint8_t {
    Access,
    OpenAt,
    Read,
    Close,
    GetTimeOfDay,
    GetPid
};

enum class RecoveredEntropySeed12f3acScenario : std::uint8_t {
    Success,
    AccessFailure,
    OpenFailure,
    ShortRead
};

struct RecoveredEntropySeed12f3acRegressionState {
    RecoveredEntropySeed12f3acScenario scenario =
            RecoveredEntropySeed12f3acScenario::Success;
    bool argumentsValid = true;
    std::vector<RecoveredEntropySeed12f3acEvent> events;
};

RecoveredEntropySeed12f3acRegressionState*&
recoveredEntropySeed12f3acRegressionState() {
    static RecoveredEntropySeed12f3acRegressionState* state = nullptr;
    return state;
}

RecoveredEntropySeed12f3acOperations
recoveredEntropySeed12f3acRegressionOperations() {
    RecoveredEntropySeed12f3acOperations operations{};
    operations.access = [](const char* path, std::int32_t mode) {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(RecoveredEntropySeed12f3acEvent::Access);
        state->argumentsValid &= std::strcmp(path, "/dev/urandom") == 0
                && mode == 4;
        return state->scenario
                == RecoveredEntropySeed12f3acScenario::AccessFailure
            ? -1 : 0;
    };
    operations.openAt = [](std::int64_t syscallNumber,
            std::int32_t directoryDescriptor,
            const char* path,
            std::int32_t flags,
            std::int32_t mode) -> std::int64_t {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(RecoveredEntropySeed12f3acEvent::OpenAt);
        state->argumentsValid &= syscallNumber == 56
                && directoryDescriptor == -100
                && std::strcmp(path, "/dev/urandom") == 0
                && flags == 0x80000 && mode == 0;
        return state->scenario
                == RecoveredEntropySeed12f3acScenario::OpenFailure
            ? -1 : 41;
    };
    operations.read = [](std::int32_t descriptor,
            void* output,
            std::size_t length) -> std::int64_t {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(RecoveredEntropySeed12f3acEvent::Read);
        state->argumentsValid &= descriptor == 41
                && output != nullptr && length == 8;
        constexpr std::uint64_t kBytes = 0x8877665544332211ULL;
        std::memcpy(output, &kBytes, sizeof(kBytes));
        return state->scenario
                == RecoveredEntropySeed12f3acScenario::ShortRead
            ? 7 : 8;
    };
    operations.close = [](std::int32_t descriptor) {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(RecoveredEntropySeed12f3acEvent::Close);
        state->argumentsValid &= descriptor == 41;
        return -1;
    };
    operations.getTimeOfDay = [](std::int64_t* seconds,
            std::int64_t* microseconds) {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(
                RecoveredEntropySeed12f3acEvent::GetTimeOfDay);
        state->argumentsValid &= seconds != nullptr
                && microseconds != nullptr;
        *seconds = 0x1122334455667788LL;
        *microseconds = static_cast<std::int64_t>(
                0x99aabbccddeeff00ULL);
        return -1;
    };
    operations.getPid = []() {
        auto* state = recoveredEntropySeed12f3acRegressionState();
        state->events.push_back(RecoveredEntropySeed12f3acEvent::GetPid);
        return static_cast<std::int32_t>(0x12345678U);
    };
    return operations;
}

bool recoveredEntropySeed12f3acRegression() {
    const auto operations = recoveredEntropySeed12f3acRegressionOperations();
    auto runScenario = [&](RecoveredEntropySeed12f3acScenario scenario,
            std::uint64_t expected,
            std::vector<RecoveredEntropySeed12f3acEvent> expectedEvents) {
        RecoveredEntropySeed12f3acRegressionState state;
        state.scenario = scenario;
        recoveredEntropySeed12f3acRegressionState() = &state;
        std::uint64_t output = 0xffffffffffffffffULL;
        runRecoveredEntropySeed12f3ac(&output, operations);
        recoveredEntropySeed12f3acRegressionState() = nullptr;
        return state.argumentsValid && output == expected
                && state.events == expectedEvents;
    };

    RecoveredEntropySeed12f3acRegressionState nullState;
    recoveredEntropySeed12f3acRegressionState() = &nullState;
    runRecoveredEntropySeed12f3ac(nullptr, operations);
    recoveredEntropySeed12f3acRegressionState() = nullptr;
    if (!nullState.events.empty()) return false;

    using Event = RecoveredEntropySeed12f3acEvent;
    constexpr std::uint64_t kFallback = 0xdef08888U;
    return runScenario(RecoveredEntropySeed12f3acScenario::Success,
                0x8877665544332211ULL,
                {Event::Access, Event::OpenAt, Event::Read, Event::Close})
            && runScenario(
                RecoveredEntropySeed12f3acScenario::AccessFailure,
                kFallback,
                {Event::Access, Event::GetTimeOfDay, Event::GetPid})
            && runScenario(
                RecoveredEntropySeed12f3acScenario::OpenFailure,
                kFallback,
                {Event::Access, Event::OpenAt,
                 Event::GetTimeOfDay, Event::GetPid})
            && runScenario(
                RecoveredEntropySeed12f3acScenario::ShortRead,
                kFallback,
                {Event::Access, Event::OpenAt, Event::Read, Event::Close,
                 Event::GetTimeOfDay, Event::GetPid});
}

Block deriveIv(std::uint32_t timeSeconds) {
    BionicRandom random(timeSeconds);
    Block iv{};
    for (std::size_t wordIndex = 0; wordIndex < 4; ++wordIndex) {
        const std::uint32_t word = random.next() ^ random.next();
        iv[wordIndex * 4] = static_cast<std::uint8_t>(word >> 24);
        iv[wordIndex * 4 + 1] = static_cast<std::uint8_t>(word >> 16);
        iv[wordIndex * 4 + 2] = static_cast<std::uint8_t>(word >> 8);
        iv[wordIndex * 4 + 3] = static_cast<std::uint8_t>(word);
    }
    return iv;
}

