std::uint32_t rotateRight(std::uint32_t value, unsigned bits) {
    return (value >> bits) | (value << (32 - bits));
}

std::uint32_t rotateLeft(std::uint32_t value, unsigned bits) {
    return (value << bits) | (value >> (32 - bits));
}

std::array<std::uint8_t, 20> sha1(
        const std::uint8_t* data,
        std::size_t size) {
    std::vector<std::uint8_t> padded;
    if (size != 0) padded.insert(padded.end(), data, data + size);
    padded.push_back(0x80);
    while ((padded.size() % 64) != 56) padded.push_back(0);
    const std::uint64_t bitLength = static_cast<std::uint64_t>(size) * 8;
    for (int shift = 56; shift >= 0; shift -= 8) {
        padded.push_back(static_cast<std::uint8_t>(bitLength >> shift));
    }

    Sha1State hash = {
        0x67452301, 0xefcdab89, 0x98badcfe, 0x10325476, 0xc3d2e1f0
    };
    for (std::size_t offset = 0; offset < padded.size(); offset += 64) {
        std::array<std::uint32_t, 80> schedule{};
        for (std::size_t i = 0; i < 16; ++i) {
            const std::uint8_t* word = padded.data() + offset + i * 4;
            schedule[i] = (static_cast<std::uint32_t>(word[0]) << 24)
                    | (static_cast<std::uint32_t>(word[1]) << 16)
                    | (static_cast<std::uint32_t>(word[2]) << 8)
                    | word[3];
        }
        for (std::size_t i = 16; i < schedule.size(); ++i) {
            schedule[i] = rotateLeft(schedule[i - 3] ^ schedule[i - 8]
                    ^ schedule[i - 14] ^ schedule[i - 16], 1);
        }

        std::uint32_t a = hash[0];
        std::uint32_t b = hash[1];
        std::uint32_t c = hash[2];
        std::uint32_t d = hash[3];
        std::uint32_t e = hash[4];
        for (std::size_t i = 0; i < schedule.size(); ++i) {
            std::uint32_t function = 0;
            std::uint32_t constant = 0;
            if (i < 20) {
                function = (b & c) | (~b & d);
                constant = 0x5a827999;
            } else if (i < 40) {
                function = b ^ c ^ d;
                constant = 0x6ed9eba1;
            } else if (i < 60) {
                function = (b & c) | (b & d) | (c & d);
                constant = 0x8f1bbcdc;
            } else {
                function = b ^ c ^ d;
                constant = 0xca62c1d6;
            }
            const std::uint32_t temporary = rotateLeft(a, 5) + function + e
                    + constant + schedule[i];
            e = d;
            d = c;
            c = rotateLeft(b, 30);
            b = a;
            a = temporary;
        }
        hash[0] += a;
        hash[1] += b;
        hash[2] += c;
        hash[3] += d;
        hash[4] += e;
    }

    std::array<std::uint8_t, 20> digest{};
    for (std::size_t i = 0; i < hash.size(); ++i) {
        digest[i * 4] = static_cast<std::uint8_t>(hash[i] >> 24);
        digest[i * 4 + 1] = static_cast<std::uint8_t>(hash[i] >> 16);
        digest[i * 4 + 2] = static_cast<std::uint8_t>(hash[i] >> 8);
        digest[i * 4 + 3] = static_cast<std::uint8_t>(hash[i]);
    }
    return digest;
}

std::array<std::uint8_t, 32> sha256WithInitialState(
        const std::uint8_t* data,
        std::size_t size,
        Sha256State hash) {
    std::vector<std::uint8_t> padded;
    if (size != 0) padded.insert(padded.end(), data, data + size);
    padded.push_back(0x80);
    while ((padded.size() % 64) != 56) padded.push_back(0);
    const std::uint64_t bitLength = static_cast<std::uint64_t>(size) * 8;
    for (int shift = 56; shift >= 0; shift -= 8) {
        padded.push_back(static_cast<std::uint8_t>(bitLength >> shift));
    }

    for (std::size_t offset = 0; offset < padded.size(); offset += 64) {
        std::array<std::uint32_t, 64> schedule{};
        for (std::size_t i = 0; i < 16; ++i) {
            const std::uint8_t* word = padded.data() + offset + i * 4;
            schedule[i] = (static_cast<std::uint32_t>(word[0]) << 24)
                    | (static_cast<std::uint32_t>(word[1]) << 16)
                    | (static_cast<std::uint32_t>(word[2]) << 8)
                    | word[3];
        }
        for (std::size_t i = 16; i < schedule.size(); ++i) {
            const std::uint32_t s0 = rotateRight(schedule[i - 15], 7)
                    ^ rotateRight(schedule[i - 15], 18) ^ (schedule[i - 15] >> 3);
            const std::uint32_t s1 = rotateRight(schedule[i - 2], 17)
                    ^ rotateRight(schedule[i - 2], 19) ^ (schedule[i - 2] >> 10);
            schedule[i] = schedule[i - 16] + s0 + schedule[i - 7] + s1;
        }

        std::uint32_t a = hash[0], b = hash[1], c = hash[2], d = hash[3];
        std::uint32_t e = hash[4], f = hash[5], g = hash[6], h = hash[7];
        for (std::size_t i = 0; i < schedule.size(); ++i) {
            const std::uint32_t big1 = rotateRight(e, 6) ^ rotateRight(e, 11) ^ rotateRight(e, 25);
            const std::uint32_t choose = (e & f) ^ (~e & g);
            const std::uint32_t temp1 = h + big1 + choose + kSha256RoundConstants[i] + schedule[i];
            const std::uint32_t big0 = rotateRight(a, 2) ^ rotateRight(a, 13) ^ rotateRight(a, 22);
            const std::uint32_t majority = (a & b) ^ (a & c) ^ (b & c);
            const std::uint32_t temp2 = big0 + majority;
            h = g; g = f; f = e; e = d + temp1;
            d = c; c = b; b = a; a = temp1 + temp2;
        }
        hash[0] += a; hash[1] += b; hash[2] += c; hash[3] += d;
        hash[4] += e; hash[5] += f; hash[6] += g; hash[7] += h;
    }

    std::array<std::uint8_t, 32> digest{};
    for (std::size_t i = 0; i < hash.size(); ++i) {
        digest[i * 4] = static_cast<std::uint8_t>(hash[i] >> 24);
        digest[i * 4 + 1] = static_cast<std::uint8_t>(hash[i] >> 16);
        digest[i * 4 + 2] = static_cast<std::uint8_t>(hash[i] >> 8);
        digest[i * 4 + 3] = static_cast<std::uint8_t>(hash[i]);
    }
    return digest;
}

std::array<std::uint8_t, 32> sha256(const std::uint8_t* data, std::size_t size) {
    constexpr Sha256State initialState = {
        0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,
        0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19
    };
    return sha256WithInitialState(data, size, initialState);
}

std::array<std::uint8_t, 32> hmacSha256(
        const std::uint8_t* key,
        std::size_t keySize,
        const std::uint8_t* message,
        std::size_t messageSize) {
    std::array<std::uint8_t, 64> keyBlock{};
    if (keySize > keyBlock.size()) {
        const auto digest = sha256(key, keySize);
        std::memcpy(keyBlock.data(), digest.data(), digest.size());
    } else {
        std::memcpy(keyBlock.data(), key, keySize);
    }
    std::vector<std::uint8_t> inner(keyBlock.size() + messageSize);
    std::vector<std::uint8_t> outer(keyBlock.size() + 32);
    for (std::size_t i = 0; i < keyBlock.size(); ++i) {
        inner[i] = static_cast<std::uint8_t>(keyBlock[i] ^ 0x36);
        outer[i] = static_cast<std::uint8_t>(keyBlock[i] ^ 0x5c);
    }
    std::memcpy(inner.data() + keyBlock.size(), message, messageSize);
    const auto innerDigest = sha256(inner.data(), inner.size());
    std::memcpy(outer.data() + keyBlock.size(), innerDigest.data(), innerDigest.size());
    return sha256(outer.data(), outer.size());
}

// Halfwords dumped from state+0x10 before libsigner.so+0x13531c. The native
// routine indexes this table in reverse bit order.
constexpr std::array<std::uint16_t, 16> kCodewordBasisInMemoryOrder = {
    0x0002,0x0022,0x0220,0x2220,0x8200,0x0a00,0x0120,0xa221,
    0x0401,0xa42a,0xb20a,0x1839,0xb824,0x0668,0xcd15,0xd0aa
};

std::uint16_t encodeCorrection(std::uint16_t code) {
    const std::uint16_t input = static_cast<std::uint16_t>(code * 2u + 3u);
    std::uint16_t output = 0;
    for (int bit = 0; bit < 16; ++bit) {
        if ((input & (1u << bit)) != 0) output ^= kCodewordBasisInMemoryOrder[15 - bit];
    }
    return output;
}

// Halfword-addressed layout consumed by libsigner.so+0x134dd8 and +0x13531c.
// Only these three regions are touched by the recovered helpers:
//
//   byte +0x10 / halfword  8: 16 codeword basis values
//   byte +0x30 / halfword 24: 64 writable correction slots
//   byte +0xb0 / halfword 88:  8 repeating unused-slot sentinels
using ProtectedCorrectionState = std::array<std::uint16_t, 96>;

// libsigner.so+0x134dd8 (x86_64 0x12f088) returns the first slot whose current
// value still equals sentinel[index & 7].  The native loop returns 64 when all
// slots differ; it does not clamp that result before the writer consumes it.
std::uint64_t findProtectedCorrectionReplacementIndex(
        const std::uint16_t* stateHalfwords) {
    std::uint64_t index = 0;
    while (index < 64
            && stateHalfwords[24 + index]
                != stateHalfwords[88 + (index & 7U)]) {
        ++index;
    }
    return index;
}

// libsigner.so+0x13531c (x86_64 0x12f489) clears the selected destination,
// then XORs state-local basis values in reverse bit order for the low 16 bits
// of 2*code+3.  Index 64 intentionally aliases halfword 88, i.e. sentinel 0,
// matching the native no-capacity-check behavior.
void writeProtectedCorrectionCodeword(
        std::uint16_t* stateHalfwords,
        std::uint32_t code,
        std::uint64_t index) {
    const std::uint16_t input = static_cast<std::uint16_t>(code * 2U + 3U);
    stateHalfwords[24 + index] = 0;
    std::uint16_t output = 0;
    for (std::uint64_t bit = 0; bit < 16; ++bit) {
        if ((input & (std::uint16_t{1} << bit)) != 0) {
            output ^= stateHalfwords[8 + (15 - bit)];
        }
    }
    stateHalfwords[24 + index] = output;
}

// Complete libsigner.so+0x13548c wrapper (x86_64 0x12f5ad): preserve the
// context pointer and code across the index lookup, then tail-call the writer.
void writeOrReplaceProtectedCorrection(
        std::uint16_t* stateHalfwords,
        std::uint32_t code) {
    const std::uint64_t index = findProtectedCorrectionReplacementIndex(
            stateHalfwords);
    writeProtectedCorrectionCodeword(stateHalfwords, code, index);
}

// Complete seed-driven correction-state initializer at
// libsigner.so+0x134a74..0x134dd8 (x86_64 +0x12edab). The caller seed is
// stored at byte zero and also seeds the Park-Miller state at byte eight.
// Sixteen samples build a permutation. Eight more samples contribute their
// high then low halfwords to a permutation-selected triangular bit matrix,
// which 0x135050 transposes in place. Codes 0x40..0x47 then initialize the
// 64 correction slots, and the first eight slots are copied to the sentinel
// region. Bytes +4..+7 are not touched by the native helper.
void runRecoveredCorrectionStateInitializer134a74(
        std::uint16_t* stateHalfwords,
        std::uint32_t seed) {
    auto* const stateBytes = reinterpret_cast<std::uint8_t*>(stateHalfwords);
    std::memcpy(stateBytes, &seed, sizeof(seed));

    std::uint64_t randomState = 0;
    recoveredParkMillerSeed12f2f8(&randomState, seed);
    const std::array<std::uint8_t, 16> permutation =
            recoveredPermutationShuffle134f40(&randomState);

    std::uint32_t sample = 0;
    for (std::size_t index = 0; index < 16; ++index) {
        if ((index & 1U) == 0) {
            sample = recoveredParkMillerNext12f298(&randomState);
        }
        const std::uint16_t selectedHalf = static_cast<std::uint16_t>(
                (index & 1U) == 0 ? sample >> 16 : sample);
        const std::uint32_t bitIndex = 15U - permutation[index];
        const std::uint16_t selectedBit = static_cast<std::uint16_t>(
                std::uint16_t{1} << bitIndex);
        stateHalfwords[8 + index] = static_cast<std::uint16_t>(
                (selectedHalf & static_cast<std::uint16_t>(selectedBit - 1U))
                | selectedBit);
    }
    recoveredCorrectionBasisTranspose135050(stateHalfwords + 8);
    std::memcpy(stateBytes + 8, &randomState, sizeof(randomState));

    for (std::size_t index = 0; index < 64; ++index) {
        writeProtectedCorrectionCodeword(stateHalfwords,
                0x40U | static_cast<std::uint32_t>(index & 7U), index);
    }
    std::copy_n(stateHalfwords + 24, 8, stateHalfwords + 88);
}

// Complete libsigner.so+0x134a1c..0x134a74 wrapper: obtain one 64-bit entropy
// value, consume its low 32 bits as the correction-state seed, and invoke the
// initializer above. The valid native caller always supplies a non-null state.
void runRecoveredCorrectionStateInitialization134a1c(
        std::uint16_t* stateHalfwords,
        const RecoveredEntropySeed12f3acOperations& operations) {
    std::uint64_t entropy = 0;
    runRecoveredEntropySeed12f3ac(&entropy, operations);
    runRecoveredCorrectionStateInitializer134a74(
            stateHalfwords, static_cast<std::uint32_t>(entropy));
}

bool recoveredCorrectionStateInitialization134a1cRegression() {
    ProtectedCorrectionState state;
    state.fill(0xa5a5U);
    runRecoveredCorrectionStateInitializer134a74(
            state.data(), 0x03020100U);

    std::uint32_t storedSeed = 0;
    std::uint64_t storedRandomState = 0;
    std::memcpy(&storedSeed, state.data(), sizeof(storedSeed));
    std::memcpy(&storedRandomState,
            reinterpret_cast<const std::uint8_t*>(state.data()) + 8,
            sizeof(storedRandomState));
    if (storedSeed != 0x03020100U
            || state[2] != 0xa5a5U || state[3] != 0xa5a5U
            || storedRandomState != 0x40617592U
            || !std::equal(kCodewordBasisInMemoryOrder.begin(),
                    kCodewordBasisInMemoryOrder.end(), state.begin() + 8)) {
        return false;
    }
    for (std::size_t index = 0; index < 64; ++index) {
        if (state[24 + index] != encodeCorrection(
                    static_cast<std::uint16_t>(0x40U | (index & 7U)))) {
            return false;
        }
    }
    if (!std::equal(state.begin() + 24, state.begin() + 32,
                state.begin() + 88)) {
        return false;
    }

    RecoveredEntropySeed12f3acRegressionState entropyState;
    recoveredEntropySeed12f3acRegressionState() = &entropyState;
    ProtectedCorrectionState wrappedState{};
    runRecoveredCorrectionStateInitialization134a1c(
            wrappedState.data(),
            recoveredEntropySeed12f3acRegressionOperations());
    recoveredEntropySeed12f3acRegressionState() = nullptr;
    std::memcpy(&storedSeed, wrappedState.data(), sizeof(storedSeed));
    std::memcpy(&storedRandomState,
            reinterpret_cast<const std::uint8_t*>(wrappedState.data()) + 8,
            sizeof(storedRandomState));
    using Event = RecoveredEntropySeed12f3acEvent;
    return entropyState.argumentsValid
            && entropyState.events == std::vector<Event>{
                Event::Access, Event::OpenAt, Event::Read, Event::Close}
            && storedSeed == 0x44332211U
            && storedRandomState == 0x708b82a9U;
}

// ARM64 native context layout consumed at libsigner.so+0x11e7b8..0x11e7f0.
// Keep fields whose semantics are not closed opaque and name the fixed byte
// regions by their final descriptor slot.  Static may-alias analysis of the
// complete context-bearing call chain proves that the pair at +0x118/+0x120
// is zero/null after memset(context+0x08, 0, 0x120) and has no producer write.
struct RecoveredArm64NativeContext {
    double timingReferenceMilliseconds;             // +0x000
    std::uint32_t timingState;                      // +0x008
    std::int32_t androidApi;                        // +0x00c
    std::uint64_t mapObject;                        // +0x010
    std::uint64_t resultByteArray;                  // +0x018
    std::array<std::uint8_t, 4> descriptor5Bytes;   // +0x020
    std::array<std::uint8_t, 12> opaque24;          // +0x024
    std::array<std::uint8_t, 32> descriptor4Bytes;  // +0x030
    std::array<std::uint8_t, 128> descriptor1Bytes; // +0x050
    std::array<std::uint8_t, 16> opaqueD0;          // +0x0d0
    std::array<std::uint8_t, 16> descriptor3Bytes;  // +0x0e0
    std::array<std::uint8_t, 20> descriptor2Bytes;  // +0x0f0
    std::array<std::uint8_t, 4> opaque104;          // +0x104
    std::uint64_t ownedPointer108;                  // +0x108
    std::uint64_t ownedPointer110;                  // +0x110
    std::uint32_t reservedDynamicLength;            // +0x118, slot 8/9
    std::uint32_t opaque11c;                        // +0x11c
    std::uint64_t reservedDynamicData;              // +0x120, slot 9
};

static_assert(sizeof(RecoveredArm64NativeContext) == 0x128);
static_assert(offsetof(RecoveredArm64NativeContext, descriptor5Bytes) == 0x20);
static_assert(offsetof(RecoveredArm64NativeContext, resultByteArray) == 0x18);
static_assert(offsetof(RecoveredArm64NativeContext, descriptor4Bytes) == 0x30);
static_assert(offsetof(RecoveredArm64NativeContext, descriptor1Bytes) == 0x50);
static_assert(offsetof(RecoveredArm64NativeContext, descriptor3Bytes) == 0xe0);
static_assert(offsetof(RecoveredArm64NativeContext, descriptor2Bytes) == 0xf0);
static_assert(offsetof(RecoveredArm64NativeContext, reservedDynamicLength) == 0x118);
static_assert(offsetof(RecoveredArm64NativeContext, reservedDynamicData) == 0x120);

struct ProtectedRealtimeSyscallSamples {
    std::int32_t clockGettimeResult = 0;
    std::int64_t clockSeconds = 0;
    std::int64_t clockNanoseconds = 0;
    std::int64_t gettimeofdaySeconds = 0;
    std::int64_t gettimeofdayMicroseconds = 0;
};

// libsigner.so+0xd184 first issues clock_gettime(CLOCK_REALTIME).  It falls
// back to gettimeofday only for the exact -ENOSYS result (-38); other errors
// retain the caller's zero-initialized timespec fields.  The gettimeofday
// return value is ignored.  ARM64 0xd334..0xd3b8 and x86_64
// 0x11626..0x1171a normalize both sources to milliseconds.
double protectedRealtimeMilliseconds(
        const ProtectedRealtimeSyscallSamples& samples) {
    std::int64_t seconds = samples.clockSeconds;
    std::int64_t nanoseconds = samples.clockNanoseconds;
    if (samples.clockGettimeResult == -38) {
        seconds = samples.gettimeofdaySeconds;
        nanoseconds = static_cast<std::int64_t>(
                static_cast<std::uint64_t>(
                    samples.gettimeofdayMicroseconds) * 1000U);
    }
    return static_cast<double>(seconds) * 1000.0
            + static_cast<double>(nanoseconds) / 1000000.0;
}

// Complete libsigner.so+0xcc47c..0xcc604 (x86_64 0xbb5b8..0xbb6ab).
// Unlike 0xd184 this helper has no -ENOSYS/gettimeofday fallback. A successful
// CLOCK_REALTIME sample is returned as milliseconds and preserves status. Any
// clock_gettime failure returns 0.0 and writes status 14 only when the status
// pointer is non-null.
double recoveredSigningContextClockMilliseconds(
        std::int32_t clockGettimeResult,
        std::int64_t seconds,
        std::int64_t nanoseconds,
        std::uint32_t* status) {
    if (clockGettimeResult != 0) {
        if (status != nullptr) *status = 14;
        return 0.0;
    }
    return static_cast<double>(seconds) * 1000.0
            + static_cast<double>(nanoseconds) / 1000000.0;
}

// Complete libsigner.so+0xd4908..0xd4e0c (x86_64 0xc1c33..0xc2115).
// Every call first invokes the timer callback synchronously.  A process-global
// byte then makes timer creation one-shot.  The installed timer uses
// CLOCK_MONOTONIC, SIGEV_THREAD and a one-second initial/periodic interval.
// Failed timer_create/timer_settime calls are ignored and leave the installed
// byte clear; the created timer is not deleted when timer_settime fails.
struct RecoveredPeriodicTimerInstallInput {
    bool installed;
    std::int32_t timerCreateResult;
    std::int32_t timerSettimeResult;
};

struct RecoveredPeriodicTimerInstallOutput {
    bool installed;
    bool synchronousCallbackCalled;
    bool timerCreateCalled;
    bool timerSettimeCalled;
    std::int32_t clockId;
    std::int32_t notificationMode;
    std::int64_t intervalSeconds;
    std::int64_t intervalNanoseconds;
    std::int64_t initialSeconds;
    std::int64_t initialNanoseconds;
};

constexpr RecoveredPeriodicTimerInstallOutput
modelRecoveredPeriodicTimerInstall(
        const RecoveredPeriodicTimerInstallInput& input) {
    RecoveredPeriodicTimerInstallOutput output{
            input.installed, true, false, false, 1, 2, 1, 0, 1, 0};
    if (input.installed) return output;
    output.timerCreateCalled = true;
    if (input.timerCreateResult == -1) return output;
    output.timerSettimeCalled = true;
    if (input.timerSettimeResult == -1) return output;
    output.installed = true;
    return output;
}

static_assert(modelRecoveredPeriodicTimerInstall({false, 0, 0}).installed);
static_assert(modelRecoveredPeriodicTimerInstall({true, -1, -1})
        .synchronousCallbackCalled);
static_assert(!modelRecoveredPeriodicTimerInstall({true, -1, -1})
        .timerCreateCalled);
static_assert(!modelRecoveredPeriodicTimerInstall({false, -1, 0})
        .timerSettimeCalled);
