// Bounded source model for libsigner.so+0xcbe98..0xcc47c. The outer descriptor
// and its four pointer slots are dereferenced by native code before this gate;
// this model begins with their already-loaded pointee values. The gate accepts
// only API >= 1 and non-null env/context/map/supplied-HMAC values. A clock
// failure returns null immediately. The certificate producer's nonzero status
// is deliberately reset before context init. The final consumer's boolean
// return is ignored: context+0x18 is returned after conditional +0x108/+0x110
// cleanup and an unconditional free(context+0x120).
constexpr RecoveredSigningContextOrchestratorOutput
modelRecoveredSigningContextOrchestrator(
        const RecoveredSigningContextOrchestratorInput& input) {
    RecoveredSigningContextOrchestratorOutput output{};
    output.state = RecoveredSigningContextState::InvalidArguments;

    if (input.androidApi < 1 || input.jniEnvironment == 0
            || input.javaContext == 0 || input.mapObject == 0
            || input.suppliedJavaHmac == 0) {
        return output;
    }

    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::ClockRealtime;
    if (input.clockGettimeResult != 0) {
        output.state = RecoveredSigningContextState::ClockFailure;
        output.statusBeforeFinalConsumer = 14;
        return output;
    }
    output.timingReferenceMilliseconds =
            static_cast<double>(input.clockSeconds) * 1000.0
            + static_cast<double>(input.clockNanoseconds) / 1000000.0;

    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::ContextInitialize;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::CertificateStage;
    output.certificateFailureStatusReset = input.certificateStageStatus != 0;
    output.statusBeforeFinalConsumer = 0;

    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::NativeContextInitStage1;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::NativeContextInitStage2;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::EnvironmentDispatcher;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::PostEnvironmentStage;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::TimingCorrectionGate;
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::FinalConsumer;

    if (input.ownedPointer108NonNull) {
        output.stages[output.stageCount++] =
                RecoveredSigningContextStage::CleanupOwned108;
        output.ownedPointer108Freed = true;
    }
    if (input.ownedPointer110NonNull) {
        output.stages[output.stageCount++] =
                RecoveredSigningContextStage::CleanupOwned110;
        output.ownedPointer110Freed = true;
    }
    output.stages[output.stageCount++] =
            RecoveredSigningContextStage::CleanupDynamic120;
    output.dynamicPointer120FreeCalled = true;
    output.resultByteArray = input.resultByteArray;
    output.state = RecoveredSigningContextState::Completed;
    return output;
}

