bool setField2FromUrandom(NativeInputs& inputs,
                          const std::vector<std::uint8_t>& urandomBytes) {
    if (urandomBytes.size() < inputs.field2.size()) return false;
    std::copy_n(urandomBytes.begin(), inputs.field2.size(), inputs.field2.begin());
    return true;
}

const std::string* findParameterValue(const ParameterEntries& parameters,
                                      const char* key) {
    const auto entry = std::find_if(parameters.begin(), parameters.end(),
            [key](const auto& candidate) { return candidate.first == key; });
    return entry == parameters.end() ? nullptr : &entry->second;
}

void setParameterValue(ParameterEntries& parameters,
                       const std::string& key,
                       const std::string& value) {
    const auto entry = std::find_if(parameters.begin(), parameters.end(),
            [&key](const auto& candidate) { return candidate.first == key; });
    if (entry == parameters.end()) parameters.emplace_back(key, value);
    else entry->second = value;
}

void appendParameterValue(std::vector<std::uint8_t>& output,
                          const ParameterEntries& parameters,
                          const char* key) {
    const std::string* value = findParameterValue(parameters, key);
    if (value == nullptr) return;
    output.insert(output.end(), value->begin(), value->end());
}

std::vector<std::uint8_t> buildNativePlaintext(const ParameterEntries& parameters) {
    std::vector<std::uint8_t> output;
    for (const char* key : kRecoveredMapPlaintextFields) {
        const char* reservedValue = recoveredReservedMapValue8af4(key);
        if (reservedValue != nullptr) {
            output.insert(output.end(), reservedValue,
                    reservedValue + std::strlen(reservedValue));
        } else {
            appendParameterValue(output, parameters, key);
        }
    }
    return output;
}

