    void (*cleanupMetadata)(std::uint32_t* status,
            std::uint64_t jniEnvironment,
            RecoveredArm64NativeContext* context);
    void (*destroyWork)(std::uint64_t work);
    void (*destroyDescriptor)(std::uint64_t descriptor);
    void (*freeMemory)(std::uint64_t pointer);
