bool recoveredFinalConsumer11da64Regression() {
    const auto operations = recoveredFinalConsumer11da64RegressionOperations();
    auto runScenario = [&](RecoveredFinalConsumer11da64Failure failure,
            std::size_t descriptorFailureIndex,
            std::uint32_t expectedStatus) {
        RecoveredArm64NativeContext context{};
        context.mapObject = 0x2222;
        context.reservedDynamicLength = 3;
        context.reservedDynamicData = 0x7777;
        std::uint32_t status = 0;
        RecoveredFinalConsumer11da64RegressionState state;
        state.failure = failure;
        state.descriptorFailureIndex = descriptorFailureIndex;
        recoveredFinalConsumer11da64RegressionState() = &state;
        const bool result = runRecoveredFinalConsumer11da64(
                0x1111, &status, &context, operations);
        recoveredFinalConsumer11da64RegressionState() = nullptr;

        constexpr std::array<std::size_t, 9> cleanupOrder = {
            2, 1, 6, 5, 0, 3, 4, 8, 7
        };
        const std::size_t successfulDescriptorCount = failure
                == RecoveredFinalConsumer11da64Failure::Descriptor
                    ? descriptorFailureIndex
                : failure == RecoveredFinalConsumer11da64Failure::Materialize
                    ? 2 : 9;
        std::vector<std::uint64_t> expectedDescriptorCleanup;
        for (std::size_t index : cleanupOrder) {
            expectedDescriptorCleanup.push_back(
                    index < successfulDescriptorCount
                        ? 0x1000 + index : 0);
        }
        const bool expectedSuccess = failure
                == RecoveredFinalConsumer11da64Failure::None;
        const std::uint64_t expectedOutput =
                expectedSuccess || failure
                        == RecoveredFinalConsumer11da64Failure::Export
                        || failure
                        == RecoveredFinalConsumer11da64Failure::Result
                    ? 0x3000 : 0;
        const bool materializationSucceeded = failure
                != RecoveredFinalConsumer11da64Failure::Materialize
                && !(failure
                        == RecoveredFinalConsumer11da64Failure::Descriptor
                        && descriptorFailureIndex < 2);
        const std::uint64_t expectedPlaintext =
                materializationSucceeded ? 0x9000 : 0;
        const bool valid = result == expectedSuccess && status == expectedStatus
                && state.argumentsValid
                && state.metadataCleanupCalled == !expectedSuccess
                && state.descriptorCleanup == expectedDescriptorCleanup
                && state.memoryCleanup
                        == std::vector<std::uint64_t>{
                            expectedOutput, expectedPlaintext};
        return valid;
    };

    return runScenario(RecoveredFinalConsumer11da64Failure::None, 0, 0)
            && runScenario(RecoveredFinalConsumer11da64Failure::Descriptor,
                    0, 4)
            && runScenario(RecoveredFinalConsumer11da64Failure::Descriptor,
                    8, 4)
            && runScenario(RecoveredFinalConsumer11da64Failure::Materialize,
                    0, 9)
            && runScenario(RecoveredFinalConsumer11da64Failure::Work, 0, 4)
            && runScenario(RecoveredFinalConsumer11da64Failure::Engine, 0, 4)
            && runScenario(
                    RecoveredFinalConsumer11da64Failure::OutputAllocation,
                    0, 2)
            && runScenario(RecoveredFinalConsumer11da64Failure::Export, 0, 4)
            && runScenario(RecoveredFinalConsumer11da64Failure::Result, 0, 9);
}

