std::int32_t nativeAtoi(const std::string& value) {
    std::size_t index = 0;
    while (index < value.size()
            && (value[index] == ' ' || (value[index] >= '\t' && value[index] <= '\r'))) {
        ++index;
    }
    bool negative = false;
    if (index < value.size() && (value[index] == '+' || value[index] == '-')) {
        negative = value[index] == '-';
        ++index;
    }
    std::uint32_t result = 0;
    while (index < value.size() && value[index] >= '0' && value[index] <= '9') {
        result = result * 10U + static_cast<std::uint32_t>(value[index] - '0');
        ++index;
    }
    if (negative) result = 0U - result;
    return static_cast<std::int32_t>(result);
}

// Recovered semantic core of the periodic callback at
// libsigner.so+0xd4e0c..0xd6888 (x86_64 0xc2115..0xc3126).  The callback
// builds /proc/<pid>/status, reads at most 0x800 bytes, searches for the
// ASCII-case-insensitive marker "TracerPid:", parses the suffix with the
// same atoi rules used elsewhere in the SO, and makes the process-global
// debugger verdict sticky when the parsed value is nonzero.  Syscall and
// one-time string-decode control flow is represented separately so static
// regression never touches the host /proc filesystem.
struct RecoveredTracerPidProbeInput {
    bool stickyTracerDetected;
    std::int32_t pathFormatResult;
    std::int32_t accessResult;
    std::int64_t openAtResult;
    std::int64_t readResult;
    std::string statusBytes;
};

struct RecoveredTracerPidProbeOutput {
    bool stickyTracerDetected;
    bool pathFormatAccepted;
    bool accessCalled;
    bool openAtCalled;
    bool readCalled;
    bool closeCalled;
    bool markerFound;
    std::int32_t parsedTracerPid;
};

std::size_t findRecoveredAsciiCaseInsensitive(
        const std::string& haystack,
        const std::string& needle) {
    if (needle.empty()) return 0;
    if (needle.size() > haystack.size()) return std::string::npos;
    for (std::size_t start = 0;
            start + needle.size() <= haystack.size(); ++start) {
        bool equal = true;
        for (std::size_t index = 0; index < needle.size(); ++index) {
            if (!protectedAsciiMarkerBytesEqual(
                        static_cast<std::uint8_t>(haystack[start + index]),
                        static_cast<std::uint8_t>(needle[index]))) {
                equal = false;
                break;
            }
        }
        if (equal) return start;
    }
    return std::string::npos;
}

RecoveredTracerPidProbeOutput modelRecoveredTracerPidProbe(
        const RecoveredTracerPidProbeInput& input) {
    RecoveredTracerPidProbeOutput output{};
    output.stickyTracerDetected = input.stickyTracerDetected;
    if (input.stickyTracerDetected) return output;

    output.pathFormatAccepted = input.pathFormatResult < 0x1000;
    if (!output.pathFormatAccepted) return output;
    output.accessCalled = true;
    if (input.accessResult != 0) return output;
    output.openAtCalled = true;
    if (input.openAtResult == -1) return output;
    output.readCalled = true;
    output.closeCalled = true;
    if (input.readResult == -1) return output;

    const std::uint64_t reportedLength = static_cast<std::uint64_t>(
            input.readResult < 0 ? 0 : input.readResult);
    const std::size_t boundedLength = static_cast<std::size_t>(
            std::min<std::uint64_t>(
                0x800U,
                std::min<std::uint64_t>(
                    reportedLength, input.statusBytes.size())));
    std::string status = input.statusBytes.substr(0, boundedLength);
    const std::size_t embeddedNul = status.find('\0');
    if (embeddedNul != std::string::npos) status.resize(embeddedNul);

    constexpr const char* kTracerMarker = "TracerPid:";
    const std::size_t marker = findRecoveredAsciiCaseInsensitive(
            status, kTracerMarker);
    if (marker == std::string::npos) return output;
    output.markerFound = true;
    output.parsedTracerPid = nativeAtoi(status.substr(
            marker + std::char_traits<char>::length(kTracerMarker)));
    if (output.parsedTracerPid != 0) output.stickyTracerDetected = true;
    return output;
}

struct RecoveredTracerPidOperations {
    std::int32_t (*getPid)();
    std::int32_t (*accessReadOnly)(const char* path);
    std::int64_t (*openAtReadOnly)(const char* path);
    std::int64_t (*readBytes)(std::int64_t descriptor,
            std::uint8_t* output,
            std::size_t capacity);
    void (*closeDescriptor)(std::int64_t descriptor);
};

void runRecoveredTracerPidPeriodicCallback(
        std::atomic<std::uint8_t>* stickyTracerDetected,
        const RecoveredTracerPidOperations& operations) {
    if (stickyTracerDetected->load(std::memory_order_relaxed) != 0) return;

    std::array<char, 0x1000> path{};
    const std::int32_t pid = operations.getPid();
    const std::int32_t pathLength = std::snprintf(
            path.data(), path.size(), "/proc/%d/status", pid);
    if (pathLength >= static_cast<std::int32_t>(path.size())) return;
    if (operations.accessReadOnly(path.data()) != 0) return;

    const std::int64_t descriptor = operations.openAtReadOnly(path.data());
    if (descriptor == -1) return;
    std::array<std::uint8_t, 0x1000> bytes{};
    const std::int64_t readResult = operations.readBytes(
            descriptor, bytes.data(), 0x800);
    operations.closeDescriptor(descriptor);
    if (readResult == -1) return;

    const std::size_t length = static_cast<std::size_t>(
            std::min<std::uint64_t>(
                0x800U, static_cast<std::uint64_t>(readResult)));
    std::string status(reinterpret_cast<const char*>(bytes.data()), length);
    const std::size_t embeddedNul = status.find('\0');
    if (embeddedNul != std::string::npos) status.resize(embeddedNul);
    constexpr const char* kTracerMarker = "TracerPid:";
    const std::size_t marker = findRecoveredAsciiCaseInsensitive(
            status, kTracerMarker);
    if (marker == std::string::npos) return;
    if (nativeAtoi(status.substr(marker
                + std::char_traits<char>::length(kTracerMarker))) != 0) {
        stickyTracerDetected->store(1, std::memory_order_relaxed);
    }
}

// Complete libsigner.so+0xd6888..0xd6994 (x86_64 0xc3126..0xc31ce).
// The callback's sticky verdict is consumed after the environment dispatcher.
// A positive verdict emits correction 0x26 and flag bit zero. Both verdicts
// then set context flag bit 38 (0x4000000000).
void applyRecoveredTracerPidPostStage(
        RecoveredArm64NativeContext* context,
        bool stickyTracerDetected) {
    if (stickyTracerDetected) {
        applyProtectedCorrectionAndFlagBit0(context, 0x26);
    }
    storeRecoveredContextFlags(context,
            loadRecoveredContextFlags(context) | 0x0000004000000000ULL);
}

// Complete front-end behavior of libsigner.so+0x12ec1c..0x12f298
// (x86_64 0x1296f4..0x129ad0). Input d0/xmm0 is epoch milliseconds and x0/rdi
// is the label. It truncates milliseconds/1000 toward zero for time_t, uses
// fmod(milliseconds, 1000) for the signed millisecond component, formats local
// time and numeric zone, then forwards one line to the separately recovered
// 0x12fa24 logging sink.
struct RecoveredTimestampLogOutput {
    std::int64_t seconds;
    std::int32_t millisecondComponent;
    std::string message;
};

RecoveredTimestampLogOutput modelRecoveredTimestampLog(
        double milliseconds,
        const std::string& label,
        const std::string& localDateTime,
        const std::string& numericZone) {
    RecoveredTimestampLogOutput output{};
    output.seconds = static_cast<std::int64_t>(milliseconds / 1000.0);
    output.millisecondComponent = static_cast<std::int32_t>(
            std::fmod(milliseconds, 1000.0));
    std::array<char, 1024> buffer{};
    std::snprintf(buffer.data(), buffer.size(), "%s: %s.%03dZ%s",
            label.c_str(), localDateTime.c_str(),
            output.millisecondComponent, numericZone.c_str());
    output.message = buffer.data();
    return output;
}

