// Complete source-level behavior of libsigner.so+0x130098..0x130128
// (x86_64 0x12a4f8..0x12a59e). This is only a varargs-to-va_list adapter for
// vsnprintf; its return value is the underlying vsnprintf return value.
std::int32_t recoveredBoundedSnprintf(
        char* destination,
        std::size_t capacity,
        const char* format,
        ...) {
    std::va_list arguments;
    va_start(arguments, format);
    const std::int32_t result = std::vsnprintf(
            destination, capacity, format, arguments);
    va_end(arguments);
    return result;
}

// Complete libsigner.so+0x11f89c..0x11f990.  The wrapper reports status 2
// when fread returns fewer than the requested item count and returns the
// native unsigned `itemsRead >= requestedCount` predicate.
bool runRecoveredFreadWrapper11f89c(
        std::uint32_t* status,
        void* destination,
        std::size_t itemSize,
        std::size_t itemCount,
        std::FILE* stream) {
    const std::size_t itemsRead = std::fread(
            destination, itemSize, itemCount, stream);
    if (itemsRead < itemCount) *status = 2;
    return itemsRead >= itemCount;
}

// Complete libsigner.so+0x11f990..0x11fa74.  Any nonzero fseek result writes
// status 2; the Boolean result is true only for zero.
bool runRecoveredFseekWrapper11f990(
        std::uint32_t* status,
        std::FILE* stream,
        long offset,
        std::int32_t origin) {
    const std::int32_t result = std::fseek(stream, offset, origin);
    if (result != 0) *status = 2;
    return result == 0;
}

// Complete libsigner.so+0x11fa74..0x11fb60.  A nonnegative ftell result is
// published to output and returns true.  A negative result leaves output
// untouched, writes status 2, and returns false.
bool runRecoveredFtellWrapper11fa74(
        std::uint32_t* status,
        std::FILE* stream,
        long* output) {
    const long result = std::ftell(stream);
    if (result < 0) {
        *status = 2;
        return false;
    }
    *output = result;
    return true;
}

