// Complete caller-visible orchestration for ARM64 0x8128..0x8ad4 and x86_64
// 0xe80a..0xf01f.  A Map or stack producer failure skips the remaining stages
// and emits correction 0x39.  A successful range-gate match emits 0x2b; a
// successful non-match emits neither correction.  Every path applies the
// 0x8ad4 flag leaf, destroys any partially published stack array, then releases
// the client_sdk copy.  Map.get returning Java null with status zero deliberately
// forwards a null source to rangeGate after a successful stack collection; a
// direct binding to protectedAndroidMarkerRangeGate therefore retains the
// original native null-dereference boundary rather than inventing an empty SDK.
void runRecoveredClientSdkStackGate8128(
        std::uint64_t jniEnvironment,
        RecoveredArm64NativeContext* context,
        const RecoveredClientSdkStackGateOperations8128& operations) {
    std::uint32_t status = 0;
    std::uint64_t clientSdk = 0;
    char** stackStrings = nullptr;
    std::uint64_t stackStringCount = 0;

    operations.copyMapString(operations.context, &status,
            jniEnvironment, context->mapObject,
            kRecoveredClientSdkMapKey8128, &clientSdk);
    if (status == 0) {
        operations.collectCurrentThreadStackStrings(operations.context,
                &status, jniEnvironment, &stackStrings,
                kRecoveredStackTraceLimit8128, &stackStringCount);
    }
    if (status == 0) {
        const bool matched = operations.rangeGate(
                kRecoveredAndroidMarker8128,
                reinterpret_cast<const char*>(
                    static_cast<std::uintptr_t>(clientSdk)),
                kRecoveredFirstClientSdkBoundary8128.data(),
                kRecoveredFirstClientSdkBoundary8128.size(),
                kRecoveredSecondClientSdkBoundary8128.data(),
                kRecoveredSecondClientSdkBoundary8128.size(),
                reinterpret_cast<const char* const*>(stackStrings),
                static_cast<std::size_t>(stackStringCount), &status);
        if (matched) applyProtectedCorrection2b(context);
    }
    if (status != 0) applyProtectedCorrection39(context);

    applyRecoveredDetectorContextFlagLeaf(
            context, kRecoveredDetectorContextFlagLeaves[0]);
    runRecoveredOwnedPointerArrayDestroyC8c44(
            reinterpret_cast<void**>(stackStrings),
            stackStringCount, operations.releaseOwned);
    operations.releaseOwned(reinterpret_cast<void*>(
            static_cast<std::uintptr_t>(clientSdk)));
}

