void recoveredClientSdkStackGateRegressionRelease8128(void* pointer) {
    auto* state = recoveredClientSdkStackGateRegressionState8128();
    auto event = RecoveredClientSdkStackGateEvent8128::UnexpectedRelease;
    if (pointer == state->originalStackPointers[0]) {
        event = RecoveredClientSdkStackGateEvent8128::ReleaseStack0;
    } else if (pointer == state->originalStackPointers[1]) {
        event = RecoveredClientSdkStackGateEvent8128::ReleaseStack1;
    } else if (pointer == state->stackPointers.data()) {
        event = RecoveredClientSdkStackGateEvent8128::ReleaseStackArray;
    } else if (pointer == state->clientSdkPointer) {
        event = RecoveredClientSdkStackGateEvent8128::ReleaseClientSdk;
    }
    state->events.push_back(event);
}

bool recoveredClientSdkStackGate8128Regression() {
    using Event = RecoveredClientSdkStackGateEvent8128;
    RecoveredClientSdkStackGateRegressionState8128 state;
    recoveredClientSdkStackGateRegressionState8128() = &state;

    const auto initializeContext = [](RecoveredArm64NativeContext* context) {
        ProtectedCorrectionState correctionState{};
        std::copy(kCodewordBasisInMemoryOrder.begin(),
                kCodewordBasisInMemoryOrder.end(),
                correctionState.begin() + 8);
        for (std::size_t sentinel = 0; sentinel < 8; ++sentinel) {
            correctionState[88 + sentinel] = static_cast<std::uint16_t>(
                    0x6000U + sentinel);
        }
        for (std::size_t slot = 0; slot < 64; ++slot) {
            correctionState[24 + slot] =
                    correctionState[88 + (slot & 7U)];
        }
        std::memcpy(reinterpret_cast<std::uint8_t*>(context) + 0x20,
                correctionState.data(), sizeof(correctionState));
    };

    const RecoveredClientSdkStackGateOperations8128 operations = {
        &state,
        recoveredClientSdkStackGateRegressionMapCopy8128,
        recoveredClientSdkStackGateRegressionCollect8128,
        recoveredClientSdkStackGateRegressionRange8128,
        recoveredClientSdkStackGateRegressionRelease8128,
    };

    const auto runScenario = [&](const std::string& clientSdk,
            bool clientSdkPresent,
            std::uint32_t mapStatus,
            std::uint32_t stackStatus,
            bool publishStackArray,
            bool safeNullRangeGate,
            std::uint32_t expectedCorrection,
            const std::vector<Event>& expectedEvents) {
        state = RecoveredClientSdkStackGateRegressionState8128{};
        state.clientSdk = clientSdk;
        state.clientSdkPresent = clientSdkPresent;
        state.mapStatus = mapStatus;
        state.stackStatus = stackStatus;
        state.publishStackArray = publishStackArray;
        state.safeNullRangeGate = safeNullRangeGate;
        for (std::size_t index = 0; index < state.stackPointers.size(); ++index) {
            state.stackPointers[index] = state.stackStorage[index].data();
            state.originalStackPointers[index] = state.stackPointers[index];
        }

        RecoveredArm64NativeContext context{};
        initializeContext(&context);
        context.mapObject = 0x3333;
        constexpr std::uint64_t initialFlags = 0x40;
        storeRecoveredContextFlags(&context, initialFlags);
        runRecoveredClientSdkStackGate8128(0x2222, &context, operations);

        ProtectedCorrectionState correctionState{};
        std::memcpy(correctionState.data(),
                reinterpret_cast<const std::uint8_t*>(&context) + 0x20,
                sizeof(correctionState));
        const std::uint16_t expectedFirst = expectedCorrection == 0
                ? static_cast<std::uint16_t>(0x6000)
                : encodeCorrection(expectedCorrection);
        const bool stackCalled = std::find(expectedEvents.begin(),
                expectedEvents.end(), Event::CollectStackStrings)
                != expectedEvents.end();
        const bool correctionApplied = expectedCorrection != 0;
        return state.events == expectedEvents
                && state.mapOutputStartedZero
                && (!stackCalled || state.stackOutputsStartedZero)
                && state.fixedInputsMatched
                && state.seenEnvironment == 0x2222
                && state.seenMapObject == 0x3333
                && (!stackCalled
                    || state.seenMaximumEntries
                        == kRecoveredStackTraceLimit8128)
                && correctionState[24] == expectedFirst
                && loadRecoveredContextFlags(&context)
                    == (initialFlags | kRecoveredClientSdkStageMask8128
                        | (correctionApplied ? 1U : 0U))
                && (!publishStackArray
                    || !stackCalled
                    || std::all_of(state.stackPointers.begin(),
                        state.stackPointers.end(),
                        [](char* value) { return value == nullptr; }));
    };

    const std::vector<Event> completeEvents = {
        Event::CopyMapString, Event::CollectStackStrings, Event::RangeGate,
        Event::ReleaseStack0, Event::ReleaseStack1,
        Event::ReleaseStackArray, Event::ReleaseClientSdk,
    };
    if (!runScenario("android5.0.0", true, 0, 0, true, false,
                0x2b, completeEvents)) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    if (!runScenario("android4.38.5", true, 0, 0, true, false,
                0, completeEvents)) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    if (!runScenario("", true, 0, 0, true, false,
                0x39, completeEvents)) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    const std::vector<Event> mapFailureEvents = {
        Event::CopyMapString, Event::ReleaseClientSdk,
    };
    if (!runScenario("ignored", true, 7, 0, true, false,
                0x39, mapFailureEvents)) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    const std::vector<Event> stackFailureEvents = {
        Event::CopyMapString, Event::CollectStackStrings,
        Event::ReleaseStack0, Event::ReleaseStack1,
        Event::ReleaseStackArray, Event::ReleaseClientSdk,
    };
    if (!runScenario("android5.0.0", true, 0, 9, true, false,
                0x39, stackFailureEvents)) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    if (!runScenario("", false, 0, 0, true, true,
                0, completeEvents) || !state.sawNullRangeSource) {
        recoveredClientSdkStackGateRegressionState8128() = nullptr;
        return false;
    }
    const std::vector<Event> noArrayEvents = {
        Event::CopyMapString, Event::CollectStackStrings, Event::RangeGate,
        Event::ReleaseClientSdk,
    };
    const bool noArray = runScenario("android5.0.0", true, 0, 0,
            false, false, 0x2b, noArrayEvents);
    recoveredClientSdkStackGateRegressionState8128() = nullptr;
    return noArray;
}

