// Complete libsigner.so+0xd6a2c..0xd6cb8.  Null path/output values and an
// access(path,R_OK) failure return false without opening.  The native helper
// then uses AArch64 syscall 56 as openat(AT_FDCWD,path,O_RDONLY,0), syscall 63
// as read(fd,output,size), and syscall 57 as close(fd).  Only an fd whose low
// 32 bits equal -1 is rejected, and only a read result exactly equal to -1 is
// failure.  Every other read result stores NUL at output[result-1] before the
// unconditional close.  storeTerminator is an explicit memory-write callback
// so the native zero-read output[-1] bug remains observable without invoking
// undefined behavior in the host regression process.
bool runRecoveredReadableFileReadD6a2c(
        const char* path,
        std::uint64_t size,
        void* output,
        const RecoveredReadableFileReadOperationsD6a2c& operations) {
    if (path == nullptr || output == nullptr) return false;
    if (operations.accessPath(path, R_OK) != 0) return false;

    const std::int64_t openResult = operations.openAt(-100, path, 0, 0);
    const std::int32_t fileDescriptor =
            static_cast<std::int32_t>(openResult);
    if (fileDescriptor == -1) return false;

    const std::int64_t readResult = operations.readFile(
            fileDescriptor, output, size);
    const bool success = readResult != -1;
    if (success) operations.storeTerminator(output, readResult - 1);
    static_cast<void>(operations.closeFile(fileDescriptor));
    return success;
}

