// Complete orchestration of libsigner.so+0x143e8..0x14e10.  Every probe uses
// the same local status slot after resetting it to zero, and no result/status
// branch suppresses later probes. Result corrections are emitted before the
// corresponding nonzero-status correction. The final context mask is applied
// unconditionally after all five probes.
void runRecoveredEnvironmentDispatcher143e8(
        RecoveredArm64NativeContext* context,
        const RecoveredEnvironmentDispatcher143e8Operations& operations) {
    std::uint32_t status = 0;

    if (operations.stageD78b8(&status, "/proc/self/maps")) {
        applyProtectedCorrectionAndFlagBit0(context, 0x22);
    }
    if (status != 0) applyProtectedCorrection35(context);

    status = 0;
    if (operations.stageDb410(&status, "/proc/self/fd")) {
        applyProtectedCorrectionAndFlagBit0(context, 0x23);
    }
    if (status != 0) applyProtectedCorrection36(context);

    if (operations.stage13063c()) {
        applyProtectedCorrectionAndFlagBit0(context, 0x25);
    }

    status = 0;
    if (operations.stage1309cc(&status)) {
        applyProtectedCorrectionAndFlagBit0(context, 0x2d);
    }
    if (status != 0) applyProtectedCorrection3aFirst(context);
    const std::uint32_t fridaServerStatus = status;

    status = 0;
    if (operations.stage1311f0(&status)) {
        applyProtectedCorrectionAndFlagBit0(context, 0x2e);
    }
    if (fridaServerStatus == 0 && status != 0) {
        applyProtectedCorrection3aSecond(context);
    }

    applyProtectedContextMask0460603c00000000(context);
}

