void removeParameter(ParameterEntries& parameters, const char* key) {
    parameters.erase(std::remove_if(parameters.begin(), parameters.end(),
            [key](const auto& entry) { return entry.first == key; }), parameters.end());
}

std::string base64NoWrap(const std::vector<std::uint8_t>& bytes) {
    static constexpr char alphabet[] =
            "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    std::string output;
    output.reserve(((bytes.size() + 2U) / 3U) * 4U);
    for (std::size_t index = 0; index < bytes.size(); index += 3) {
        const std::size_t remaining = bytes.size() - index;
        const std::uint32_t word = static_cast<std::uint32_t>(bytes[index]) << 16
                | (remaining > 1 ? static_cast<std::uint32_t>(bytes[index + 1]) << 8 : 0U)
                | (remaining > 2 ? bytes[index + 2] : 0U);
        output.push_back(alphabet[(word >> 18) & 0x3fU]);
        output.push_back(alphabet[(word >> 12) & 0x3fU]);
        output.push_back(remaining > 1 ? alphabet[(word >> 6) & 0x3fU] : '=');
        output.push_back(remaining > 2 ? alphabet[word & 0x3fU] : '=');
    }
    return output;
}

// Recovered from com.adjust.sdk.sig.d. This is the platform-neutral observable
// control flow around the native signer: the Android adapter supplies the two
// key-operation outcomes, reset outcomes and native result. It deliberately
// preserves the unusual reset-failure behavior: resetKey() throws from inside
// the retriable catch, so activity_kind/client_sdk remain inserted in that case.
RecoveredSignerFlowOutput runRecoveredSignerFlow(
        bool& processLockdown,
        ParameterEntries& parameters,
        const RecoveredSignerFlowInput& input) {
    if (processLockdown) {
        return {RecoveredSignerFlowResult::LockedDownEarly, 0, 0};
    }
    if (!input.parametersPresent || parameters.empty()
            || !input.activityKindPresent || !input.clientSdkPresent) {
        return {RecoveredSignerFlowResult::InvalidArguments, 0, 0};
    }

    setParameterValue(parameters, "activity_kind", input.activityKind);
    setParameterValue(parameters, "client_sdk", input.clientSdk);
    const auto removeTemporaryKeys = [&parameters]() {
        removeParameter(parameters, "activity_kind");
        removeParameter(parameters, "client_sdk");
    };

    std::size_t attemptsUsed = 0;
    std::size_t resetCount = 0;
    bool keyReady = false;
    for (std::size_t attempt = 0; attempt < 2; ++attempt) {
        ++attemptsUsed;
        const RecoveredKeyAttemptStatus status = attempt < input.keyAttempts.size()
                ? input.keyAttempts[attempt]
                : RecoveredKeyAttemptStatus::OtherException;
        if (status == RecoveredKeyAttemptStatus::Success) {
            keyReady = true;
            break;
        }
        if (status == RecoveredKeyAttemptStatus::UnsupportedApi) {
            processLockdown = true;
            removeTemporaryKeys();
            return {RecoveredSignerFlowResult::UnsupportedApiRethrown,
                    attemptsUsed, resetCount};
        }
        if (status == RecoveredKeyAttemptStatus::InvalidKey
                || status == RecoveredKeyAttemptStatus::UnrecoverableKey) {
            const bool resetOk = resetCount < input.resetSucceeded.size()
                    ? input.resetSucceeded[resetCount]
                    : false;
            ++resetCount;
            if (!resetOk) {
                return {RecoveredSignerFlowResult::ResetExceptionRethrown,
                        attemptsUsed, resetCount};
            }
            continue;
        }
        removeTemporaryKeys();
        return {RecoveredSignerFlowResult::OtherExceptionRethrown,
                attemptsUsed, resetCount};
    }

    if (!keyReady) {
        processLockdown = true;
        removeTemporaryKeys();
        return {RecoveredSignerFlowResult::RetriesExhausted,
                attemptsUsed, resetCount};
    }
    if (!input.nativeSignatureReturned) {
        removeTemporaryKeys();
        return {RecoveredSignerFlowResult::NullNativeSignature,
                attemptsUsed, resetCount};
    }

    setParameterValue(parameters, "signature", base64NoWrap(input.nativeSignature));
    removeTemporaryKeys();
    return {RecoveredSignerFlowResult::Signed, attemptsUsed, resetCount};
}

void applyJavaHmacCorrection(std::vector<std::uint16_t>& corrections,
                             const std::vector<std::uint8_t>& key,
                             const std::vector<std::uint8_t>& mapStringUtf8,
                             const std::vector<std::uint8_t>& suppliedHmac) {
    // ARM64 closes the expected side too: 0x9b684 calls Map.toString(), 0x9c030
    // calls the no-argument String.getBytes(), 0xc8ec0 selects the API-specific
    // Key route, and 0xca648 invokes Java Mac.getInstance/init/update/doFinal.
    // With a resolved raw key, the cryptographic equivalent is this HMAC. The
    // parameter name is retained for CLI compatibility; bytes must actually be
    // the Android default-charset result, which is UTF-8 on the target runtime.
    const auto expected = hmacSha256(key.data(), key.size(),
            mapStringUtf8.data(), mapStringUtf8.size());
    const std::vector<std::uint8_t> expectedBytes(expected.begin(), expected.end());
    const bool mismatch = !constantTimeEqual(expectedBytes, suppliedHmac);
    const auto existing = std::find(corrections.begin(), corrections.end(), 0x07);
    if (!mismatch) {
        if (existing != corrections.end()) corrections.erase(existing);
        return;
    }
    if (existing != corrections.end()) return;
    const auto initialization = std::find(corrections.begin(), corrections.end(), 0x2b);
    corrections.insert(initialization == corrections.end() ? corrections.begin()
            : initialization + 1, 0x07);
}

enum class RecoveredJavaHmacIntegrityOutcome : std::uint8_t {
    SkippedFailOpen,
    Match,
    MismatchCorrection07
};

constexpr RecoveredJavaHmacIntegrityOutcome classifyRecoveredJavaHmacIntegrity(
        bool suppliedCopySucceeded,
        bool objectToStringSucceeded,
        bool keyResolverSucceeded,
        bool getBytesSucceeded,
        bool macProducerSucceeded,
        bool bytesMatch) {
    if (!suppliedCopySucceeded || !objectToStringSucceeded || !keyResolverSucceeded
            || !getBytesSucceeded || !macProducerSucceeded) {
        return RecoveredJavaHmacIntegrityOutcome::SkippedFailOpen;
    }
    return bytesMatch ? RecoveredJavaHmacIntegrityOutcome::Match
            : RecoveredJavaHmacIntegrityOutcome::MismatchCorrection07;
}

void applyRecoveredJavaHmacIntegrityOutcome(
        std::vector<std::uint16_t>& corrections,
        RecoveredJavaHmacIntegrityOutcome outcome) {
    if (outcome == RecoveredJavaHmacIntegrityOutcome::SkippedFailOpen) return;
    const auto existing = std::find(corrections.begin(), corrections.end(), 0x07);
    if (outcome == RecoveredJavaHmacIntegrityOutcome::Match) {
        if (existing != corrections.end()) corrections.erase(existing);
        return;
    }
    if (existing != corrections.end()) return;
    const auto initialization = std::find(corrections.begin(), corrections.end(), 0x2b);
    corrections.insert(initialization == corrections.end() ? corrections.begin()
            : initialization + 1, 0x07);
}

